    from collections import deque
    class Solution:
        def canVisitAllRooms(self, rooms: List[List[int]]) -> bool:
            if not rooms:
                return True
            n = len(rooms)
            visited = set()
            queue = deque()
            queue.append(0)
            visited.add(0)

            while queue:
                current_room = queue.popleft()
                for key in rooms[current_room]:
                    if key not in visited:
                        visited.add(key)
                        queue.append(key)
            return len(visited) == n
